-- 041 — item_canonico_id: agrupa aparições do MESMO item (mesmo enunciado) entre
-- níveis/provas. É a base de ÂNCORAS para o linking do TRI (v2 da dificuldade
-- absoluta) e para reuso de material entre níveis. null = item sem gêmeo cross-nível.
-- Backfill abaixo: 79 itens canônicos (184 aparições) detectados no acervo por
-- similaridade de enunciado >=0.95 dentro de (olimpiada, ano, fase), níveis distintos.

ALTER TABLE questao ADD COLUMN IF NOT EXISTS item_canonico_id uuid;
CREATE INDEX IF NOT EXISTS idx_questao_item_canonico ON questao (item_canonico_id);
COMMENT ON COLUMN questao.item_canonico_id IS
  'Agrupa aparicoes do MESMO item entre niveis/provas (ancora p/ linking TRI). null = sem gemeo cross-nivel.';

